// Parse and validate compliance check request
const request = $input.first().json;

// Validate required fields
const requiredFields = ['content_type', 'content_data', 'platforms', 'target_regions'];
const missingFields = requiredFields.filter(field => !request[field]);

if (missingFields.length > 0) {
  return {
    json: {
      error: `Missing required fields: ${missingFields.join(', ')}`,
      valid: false,
      request_id: request.request_id || `comp_${Date.now()}`
    }
  };
}

// Determine check type based on content
let checkType = 'standard';
if (request.content_type === 'affiliate_offer') {
  checkType = 'affiliate';
} else if (request.content_type === 'financial_advice') {
  checkType = 'financial';
} else if (request.content_type === 'health_advice') {
  checkType = 'health';
} else if (request.content_type.includes('crypto') || request.content_type.includes('investment')) {
  checkType = 'financial';
}

// Extract content for analysis
const contentText = typeof request.content_data === 'string' ? 
  request.content_data : 
  JSON.stringify(request.content_data);

return {
  json: {
    valid: true,
    request_id: request.request_id || `comp_${Date.now()}`,
    check_type: checkType,
    content_type: request.content_type,
    platforms: Array.isArray(request.platforms) ? request.platforms : [request.platforms],
    target_regions: Array.isArray(request.target_regions) ? request.target_regions : [request.target_regions],
    content_text: contentText.substring(0, 10000), // Limit size
    metadata: request.metadata || {},
    urgency: request.urgency || 'normal',
    submitted_by: request.submitted_by || 'unknown',
    submitted_at: new Date().toISOString()
  }
};

// Perform affiliate-specific compliance checks
const request = $input.first().json;
const content = request.content_text.toLowerCase();
const regions = request.target_regions.map(r => r.toLowerCase());

const checks = {
  ftc_disclosure: false,
  clear_terms: false,
  no_misleading_claims: false,
  proper_disclaimer: false,
  region_specific: {}
};

// FTC disclosure check (US)
if (regions.includes('us') || regions.includes('usa') || regions.includes('united states')) {
  const ftcKeywords = ['affiliate', 'commission', 'sponsored', 'ad', '#ad', '#sponsored'];
  checks.ftc_disclosure = ftcKeywords.some(keyword => content.includes(keyword));
}

// Clear terms check
const termsKeywords = ['terms', 'conditions', 'disclaimer', 'policy'];
checks.clear_terms = termsKeywords.some(keyword => content.includes(keyword));

// No misleading claims check
const misleadingPhrases = [
  'get rich quick',
  'guaranteed results',
  'risk free',
  'no risk',
  'instant success',
  'overnight success'
];
checks.no_misleading_claims = !misleadingPhrases.some(phrase => content.includes(phrase));

// Proper disclaimer check
const disclaimerPhrases = [
  'results may vary',
  'individual results',
  'not financial advice',
  'consult professional'
];
checks.proper_disclaimer = disclaimerPhrases.some(phrase => content.includes(phrase));

// Region-specific checks
for (const region of regions) {
  checks.region_specific[region] = {
    passed: true,
    requirements: []
  };

  // EU GDPR requirements
  if (region.includes('eu') || region.includes('europe')) {
    checks.region_specific[region].requirements.push('gdpr_compliance');
    // Check for privacy policy mention
    if (!content.includes('privacy') && !content.includes('gdpr')) {
      checks.region_specific[region].passed = false;
    }
  }

  // UK requirements
  if (region.includes('uk') || region.includes('united kingdom')) {
    checks.region_specific[region].requirements.push('asa_compliance');
    // ASA requires clear identification of marketing
    if (!content.includes('ad') && !content.includes('advert')) {
      checks.region_specific[region].passed = false;
    }
  }
}

// Calculate overall score
const totalChecks = Object.keys(checks).filter(k => k !== 'region_specific').length;
const passedChecks = Object.entries(checks)
  .filter(([key, value]) => key !== 'region_specific' && value === true)
  .length;

const regionChecks = Object.values(checks.region_specific);
const regionPassed = regionChecks.filter(r => r.passed).length;
const regionTotal = regionChecks.length;

const overallScore = Math.round(
  ((passedChecks / totalChecks) * 0.7 + (regionPassed / Math.max(regionTotal, 1)) * 0.3) * 100
);

const result = {
  check_type: 'affiliate',
  checks_performed: checks,
  overall_score: overallScore,
  passed: overallScore >= 70,
  warnings: [],
  required_actions: []
};

// Generate warnings
if (!checks.ftc_disclosure && regions.some(r => r.includes('us'))) {
  result.warnings.push('Missing FTC disclosure for US audience');
  result.required_actions.push('Add "#ad" or "affiliate link" disclosure');
}

if (!checks.no_misleading_claims) {
  result.warnings.push('Contains potentially misleading claims');
  result.required_actions.push('Remove or qualify exaggerated claims');
}

// Check region-specific failures
for (const [region, regionCheck] of Object.entries(checks.region_specific)) {
  if (!regionCheck.passed) {
    result.warnings.push(`Failed ${region} specific requirements: ${regionCheck.requirements.join(', ')}`);
    result.required_actions.push(`Add ${region} compliance statements`);
  }
}

return result;

// Perform financial compliance checks
const request = $input.first().json;
const content = request.content_text.toLowerCase();
const regions = request.target_regions.map(r => r.toLowerCase());

const checks = {
  risk_disclosure: false,
  not_advice_disclaimer: false,
  past_performance_disclaimer: false,
  no_guarantees: false,
  regulatory_compliance: {}
};

// Risk disclosure check
const riskKeywords = ['risk', 'volatile', 'uncertain', 'speculative', 'loss'];
checks.risk_disclosure = riskKeywords.some(keyword => content.includes(keyword));

// Not financial advice disclaimer
const adviceKeywords = ['not financial advice', 'not investment advice', 'consult professional', 'for educational purposes'];
checks.not_advice_disclaimer = adviceKeywords.some(keyword => content.includes(keyword));

// Past performance disclaimer
const pastPerfKeywords = ['past performance', 'historical results', 'not indicative', 'future results'];
checks.past_performance_disclaimer = pastPerfKeywords.some(keyword => content.includes(keyword));

// No guarantees check
const guaranteePhrases = ['guaranteed', '100% sure', 'cannot lose', 'risk-free'];
checks.no_guarantees = !guaranteePhrases.some(phrase => content.includes(phrase));

// Regulatory compliance by region
for (const region of regions) {
  checks.regulatory_compliance[region] = {
    passed: true,
    regulations: []
  };

  // US SEC/FINRA requirements
  if (region.includes('us')) {
    checks.regulatory_compliance[region].regulations.push('sec', 'finra');
    // Check for proper disclosures
    if (!content.includes('sec') && !content.includes('registered')) {
      checks.regulatory_compliance[region].passed = false;
    }
  }

  // UK FCA requirements
  if (region.includes('uk')) {
    checks.regulatory_compliance[region].regulations.push('fca');
    if (!content.includes('fca') && !content.includes('authorised')) {
      checks.regulatory_compliance[region].passed = false;
    }
  }

  // EU MiFID requirements
  if (region.includes('eu')) {
    checks.regulatory_compliance[region].regulations.push('mifid');
    if (!content.includes('mifid') && !content.includes('investment firm')) {
      checks.regulatory_compliance[region].passed = false;
    }
  }
}

// Calculate overall score
const totalChecks = Object.keys(checks).filter(k => k !== 'regulatory_compliance').length;
const passedChecks = Object.entries(checks)
  .filter(([key, value]) => key !== 'regulatory_compliance' && value === true)
  .length;

const regChecks = Object.values(checks.regulatory_compliance);
const regPassed = regChecks.filter(r => r.passed).length;
const regTotal = regChecks.length;

const overallScore = Math.round(
  ((passedChecks / totalChecks) * 0.6 + (regPassed / Math.max(regTotal, 1)) * 0.4) * 100
);

const result = {
  check_type: 'financial',
  checks_performed: checks,
  overall_score: overallScore,
  passed: overallScore >= 80, // Higher threshold for financial
  warnings: [],
  required_actions: [],
  high_risk: false
};

// Generate warnings and determine risk level
if (!checks.risk_disclosure) {
  result.warnings.push('Missing risk disclosure');
  result.required_actions.push('Add risk warning statement');
  result.high_risk = true;
}

if (!checks.not_advice_disclaimer) {
  result.warnings.push('Missing "not financial advice" disclaimer');
  result.required_actions.push('Add clear disclaimer that this is not financial advice');
  result.high_risk = true;
}

if (!checks.no_guarantees) {
  result.warnings.push('Contains guarantee language');
  result.required_actions.push('Remove guarantee language');
  result.high_risk = true;
}

// Check regulatory failures
for (const [region, regCheck] of Object.entries(checks.regulatory_compliance)) {
  if (!regCheck.passed) {
    result.warnings.push(`Failed ${region} regulatory requirements: ${regCheck.regulations.join(', ')}`);
    result.required_actions.push(`Add ${region} regulatory disclosures`);
    result.high_risk = true;
  }
}

return result;

// Perform standard compliance checks
const request = $input.first().json;
const content = request.content_text.toLowerCase();
const platforms = request.platforms.map(p => p.toLowerCase());

const checks = {
  no_hate_speech: true,
  no_harassment: true,
  appropriate_content: true,
  copyright_compliance: true,
  platform_specific: {}
};

// Hate speech check
const hateTerms = [
  'hate', 'racist', 'sexist', 'homophobic', 'transphobic',
  'discriminat', 'bigot', 'slur', 'offensive'
];
checks.no_hate_speech = !hateTerms.some(term => content.includes(term));

// Harassment check
const harassmentTerms = [
  'bully', 'threat', 'intimidat', 'stalk', 'harass'
];
checks.no_harassment = !harassmentTerms.some(term => content.includes(term));

// Appropriate content check
const inappropriateTerms = [
  'explicit', 'porn', 'nsfw', 'adult', 'violence', 'gore'
];
checks.appropriate_content = !inappropriateTerms.some(term => content.includes(term));

// Copyright check (basic)
const copyrightPhrases = [
  'copyright', 'all rights reserved', '©', 'trademark', '™', 'registered', '®'
];
checks.copyright_compliance = !copyrightPhrases.some(phrase => content.includes(phrase)) || 
  content.includes('fair use') || content.includes('licensed');

// Platform-specific checks
for (const platform of platforms) {
  checks.platform_specific[platform] = {
    passed: true,
    requirements: []
  };

  // YouTube specific
  if (platform.includes('youtube')) {
    checks.platform_specific[platform].requirements.push('community_guidelines');
    // Check for monetization suitability
    if (content.includes('controversial') || content.includes('sensitive')) {
      checks.platform_specific[platform].passed = false;
    }
  }

  // Twitter/X specific
  if (platform.includes('twitter') || platform.includes('x')) {
    checks.platform_specific[platform].requirements.push('twitter_rules');
    // Check for misinformation
    const misinfoTerms = ['fake news', 'conspiracy', 'hoax'];
    if (misinfoTerms.some(term => content.includes(term))) {
      checks.platform_specific[platform].passed = false;
    }
  }

  // LinkedIn specific
  if (platform.includes('linkedin')) {
    checks.platform_specific[platform].requirements.push('professional_standards');
    // Check for professional tone
    if (content.includes('casual') || content.includes('informal')) {
      checks.platform_specific[platform].passed = false;
    }
  }
}

// Calculate overall score
const totalChecks = Object.keys(checks).filter(k => k !== 'platform_specific').length;
const passedChecks = Object.entries(checks)
  .filter(([key, value]) => key !== 'platform_specific' && value === true)
  .length;

const platformChecks = Object.values(checks.platform_specific);
const platformPassed = platformChecks.filter(p => p.passed).length;
const platformTotal = platformChecks.length;

const overallScore = Math.round(
  ((passedChecks / totalChecks) * 0.8 + (platformPassed / Math.max(platformTotal, 1)) * 0.2) * 100
);

const result = {
  check_type: 'standard',
  checks_performed: checks,
  overall_score: overallScore,
  passed: overallScore >= 60,
  warnings: [],
  required_actions: []
};

// Generate warnings
if (!checks.no_hate_speech) {
  result.warnings.push('Potential hate speech detected');
  result.required_actions.push('Review and remove offensive content');
}

if (!checks.appropriate_content) {
  result.warnings.push('Inappropriate content detected');
  result.required_actions.push('Make content appropriate for all audiences');
}

// Check platform-specific failures
for (const [platform, platformCheck] of Object.entries(checks.platform_specific)) {
  if (!platformCheck.passed) {
    result.warnings.push(`Failed ${platform} specific requirements`);
    result.required_actions.push(`Adjust content for ${platform} guidelines`);
  }
}

return result;

// Process auto-approved content
const complianceResult = $input.first().json;
const originalRequest = $node["Parse Compliance Request"].json;

const approvalRecord = {
  request_id: originalRequest.request_id,
  content_type: originalRequest.content_type,
  check_type: complianceResult.check_type,
  status: 'auto_approved',
  approved_at: new Date().toISOString(),
  approved_by: 'compliance_system',
  score: complianceResult.overall_score,
  warnings: complianceResult.warnings || [],
  notes: 'Automatically approved by compliance system',
  requires_monitoring: complianceResult.warnings && complianceResult.warnings.length > 0
};

// Send to SIMP broker
const approvalPayload = {
  intent_type: 'compliance_approval',
  source_agent: 'n8n_workflow',
  target_agent: 'base_media_agent',
  payload: approvalRecord
};

return {
  json: {
    approval_record: approvalRecord,
    approval_payload: approvalPayload,
    should_notify: true,
    next_step: 'proceed_with_publishing'
  }
};

// Route to human review
const complianceResult = $input.first().json;
const originalRequest = $node["Parse Compliance Request"].json;

const reviewRequest = {
  request_id: originalRequest.request_id,
  content_type: originalRequest.content_type,
  check_type: complianceResult.check_type,
  status: 'requires_review',
  submitted_at: originalRequest.submitted_at,
  submitted_by: originalRequest.submitted_by,
  score: complianceResult.overall_score,
  warnings: complianceResult.warnings || [],
  required_actions: complianceResult.required_actions || [],
  high_risk: complianceResult.high_risk || false,
  urgency: originalRequest.urgency || 'normal',
  review_deadline: new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString(), // 24 hours
  assigned_to: null // To be assigned by human
};

// Determine priority
let priority = 'medium';
if (reviewRequest.high_risk) priority = 'high';
if (reviewRequest.urgency === 'urgent') priority = 'critical';
if (reviewRequest.urgency === 'low') priority = 'low';

reviewRequest.priority = priority;

// Send to SIMP broker for human review queue
const reviewPayload = {
  intent_type: 'compliance_review_request',
  source_agent: 'n8n_workflow',
  target_agent: 'compliance_agent',
  payload: reviewRequest
};

// Also send notification
const notification = {
  type: 'compliance_review_required',
  priority: priority,
  request_id: reviewRequest.request_id,
  content_type: reviewRequest.content_type,
  score: reviewRequest.score,
  warnings_count: reviewRequest.warnings.length,
  review_deadline: reviewRequest.review_deadline
};

return {
  json: {
    review_request: reviewRequest,
    review_payload: reviewPayload,
    notification: notification,
    should_escalate: priority === 'critical' || priority === 'high',
    next_step: 'await_human_review'
  }
};

