// Generate compliance workflow report
const allResults = $input.all();

const report = {
  timestamp: new Date().toISOString(),
  workflow: 'compliance_check',
  summary: {
    total_processed: allResults.length,
    auto_approved: 0,
    requires_review: 0,
    average_score: 0,
    by_check_type: {},
    by_content_type: {}
  },
  recent_requests: []
};

let totalScore = 0;

for (const result of allResults) {
  const data = result.json;

  // Count by status
  if (data.status === 'auto_approved' || data.approval_record) {
    report.summary.auto_approved++;
  } else if (data.status === 'requires_review' || data.review_request) {
    report.summary.requires_review++;
  }

  // Track scores
  const score = data.overall_score || data.score || 0;
  totalScore += score;

  // Count by check type
  const checkType = data.check_type || 'unknown';
  if (!report.summary.by_check_type[checkType]) {
    report.summary.by_check_type[checkType] = 0;
  }
  report.summary.by_check_type[checkType]++;

  // Count by content type
  const contentType = data.content_type || 'unknown';
  if (!report.summary.by_content_type[contentType]) {
    report.summary.by_content_type[contentType] = 0;
  }
  report.summary.by_content_type[contentType]++;

  // Add to recent requests
  report.recent_requests.push({
    request_id: data.request_id || data.approval_record?.request_id || data.review_request?.request_id,
    check_type: checkType,
    content_type: contentType,
    score: score,
    status: data.status || (data.approval_record ? 'auto_approved' : 'requires_review'),
    timestamp: data.submitted_at || new Date().toISOString()
  });
}

report.summary.average_score = allResults.length > 0 ? 
  Math.round(totalScore / allResults.length) : 0;

// Limit recent requests
report.recent_requests = report.recent_requests.slice(-10);

// Send to SIMP broker
const reportPayload = {
  intent_type: 'compliance_workflow_report',
  source_agent: 'n8n_workflow',
  target_agent: 'base_media_agent',
  payload: report
};

return {
  json: {
    report: report,
    report_payload: reportPayload,
    should_send_report: true
  }
};
